input.old_string:
locals {
  uami_name = coalesce(var.uami_name_override, "id-${var.env_name}-wif")
  fic_name  = coalesce(var.fic_name_override, "fic-${var.service_connection_name}")

  fic_subject = "sc://${var.ado_org_name}/${var.ado_project_name}/${var.service_connection_name}"
  fic_issuer  = "https://vstoken.dev.azure.com/${var.ado_collection_id}"
}

input.new_string:
locals {
  # Treat empty string as unset so `uami_name_override = ""` falls back to the computed default
  # instead of producing an API error on an empty resource name.
  uami_name = var.uami_name_override != null && var.uami_name_override != "" ? var.uami_name_override : "id-${var.env_name}-wif"

  # FIC default: fic-<ado_org>-<env>-wif (CAF-aligned per AVM SNFR25 "sensible prefix" guidance;
  # federatedIdentityCredentials has no CAF abbreviation, so `fic-` is the module-defined prefix).
  fic_name = "fic-${var.ado_org_name}-${var.env_name}-wif"

  fic_subject = "sc://${var.ado_org_name}/${var.ado_project_name}/${var.service_connection_name}"
  fic_issuer  = "https://vstoken.dev.azure.com/${var.ado_collection_id}"
}

input.old_string:
variable "service_connection_name" {
  type        = string
  description = "Azure DevOps service connection name that will federate to this UAMI (e.g., sc-cafehyna-dev-wif). Load-bearing contract per ADR 010 §2 Decision 6 — renaming breaks the FIC with AADSTS700213."

  validation {
    condition     = length(var.service_connection_name) > 0
    error_message = "service_connection_name must not be empty."
  }
}

variable "ado_collection_id" {
  type        = string
  description = "ADO organization's collection instance ID (GUID). Used to build the FIC issuer URL: https://vstoken.dev.azure.com/<ado_collection_id>. Read-only lookup via: az devops invoke --org https://dev.azure.com/<org> --area core --resource-path connectionData --query 'instanceId' -o tsv."

  validation {
    condition     = can(regex("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$", var.ado_collection_id))
    error_message = "ado_collection_id must be a GUID (8-4-4-4-12 hex)."
  }
}

input.new_string:
variable "service_connection_name" {
  type        = string
  description = "Azure DevOps service connection name that will federate to this UAMI (e.g., sc-cafehyna-dev-wif). Load-bearing contract per ADR 010 §2 Decision 6 — renaming breaks the FIC with AADSTS700213. Must match ^sc-[a-z0-9-]+-wif$ to enforce the ADR registry shape."

  validation {
    condition     = can(regex("^sc-[a-z0-9-]+-wif$", var.service_connection_name))
    error_message = "service_connection_name must match ^sc-[a-z0-9-]+-wif$ (lowercase, starts with sc-, ends with -wif; per ADR 010 §4 registry)."
  }
}

variable "ado_collection_id" {
  type        = string
  sensitive   = true
  description = "ADO organization's collection instance ID (GUID). Used to build the FIC issuer URL: https://vstoken.dev.azure.com/<ado_collection_id>. Read-only lookup via: az devops invoke --org https://dev.azure.com/<org> --area core --resource-path connectionData --query 'instanceId' -o tsv. Azure emits lowercase GUIDs; uppercase is rejected to prevent case drift in the issuer URL."

  validation {
    condition     = can(regex("^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$", var.ado_collection_id))
    error_message = "ado_collection_id must be a lowercase GUID (8-4-4-4-12 hex, [0-9a-f])."
  }
}

input.old_string:
variable "uami_name_override" {
  type        = string
  description = "Optional explicit UAMI name. When null, the module computes id-<env_name>-wif per ADR 010 §2 Decision 2 and §4."
  default     = null
}

variable "fic_name_override" {
  type        = string
  description = "Optional explicit FIC name. When null, the module computes fic-<service_connection_name> per ADR 010 §4 registry."
  default     = null
}

input.new_string:
variable "uami_name_override" {
  type        = string
  description = "Optional explicit UAMI name. When null or empty, the module computes id-<env_name>-wif per ADR 010 §2 Decision 2 and §4 (CAF abbreviation 'id' for Microsoft.ManagedIdentity/userAssignedIdentities). AVM SNFR25 mandates this override escape hatch. Changing this after bootstrap forces UAMI recreate — coordinate with ADO and Entra."
  default     = null
}

input.old_string:
output "fic_name" {
  description = "Computed FIC name (fic-<service_connection_name> unless overridden)."
  value       = azurerm_federated_identity_credential.this.name
}

output "fic_subject" {
  description = "Rendered FIC subject claim string. Must match sc://<ado_org>/<ado_project>/<service_connection_name> exactly — Story 10-2 AC #13 verifies this byte-for-byte before the bootstrap apply."
  value       = azurerm_federated_identity_credential.this.subject
}

output "fic_issuer" {
  description = "Rendered FIC issuer URL (https://vstoken.dev.azure.com/<ado_collection_id>). Used by Story 10-4 to validate the service connection's OIDC configuration."
  value       = azurerm_federated_identity_credential.this.issuer
}

input.new_string:
output "fic_subject" {
  description = "Rendered FIC subject claim string. Must match sc://<ado_org>/<ado_project>/<service_connection_name> exactly — Story 10-2 AC #13 verifies this byte-for-byte before the bootstrap apply."
  value       = azurerm_federated_identity_credential.this.subject
}

output "fic_issuer" {
  description = "Rendered FIC issuer URL (https://vstoken.dev.azure.com/<ado_collection_id>). Used by Story 10-4 to validate the service connection's OIDC configuration. Sensitive because the URL embeds the ADO collection GUID which is marked sensitive upstream."
  value       = azurerm_federated_identity_credential.this.issuer
  sensitive   = true
}
